import java.util.Scanner;
class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        double[] nums = new double[n];
        double sum = 0;
        for (int i = 0; i < n; i++) { nums[i] = sc.nextDouble(); sum += nums[i]; }
        double mean = sum / n;
        double var = 0;
        for (double x : nums) var += (x - mean) * (x - mean);
        System.out.println(String.format("%.4f", Math.sqrt(var / n)));
    }
}

