import java.util.Scanner;
class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        StringBuilder sb = new StringBuilder();
        for (int d = 2; d * d <= n; d++) {
            if (n % d == 0) {
                if (sb.length() > 0) sb.append(" ");
                sb.append(d);
                while (n % d == 0) n /= d;
            }
        }
        if (n > 1) {
            if (sb.length() > 0) sb.append(" ");
            sb.append(n);
        }
        System.out.println(sb);
    }
}

