import java.util.*;
class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        Set<Integer> seen = new HashSet<>(), dupes = new TreeSet<>();
        for (int i = 0; i < n; i++) {
            int x = sc.nextInt();
            if (!seen.add(x)) dupes.add(x);
        }
        if (dupes.isEmpty()) System.out.println("NONE");
        else {
            StringBuilder sb = new StringBuilder();
            for (int d : dupes) {
                if (sb.length() > 0) sb.append(" ");
                sb.append(d);
            }
            System.out.println(sb);
        }
    }
}

import java.util.*;
class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n1 = sc.nextInt();
        Set<Integer> s1 = new TreeSet<>();
        for (int i = 0; i < n1; i++) s1.add(sc.nextInt());
        int n2 = sc.nextInt();
        Set<Integer> s2 = new HashSet<>();
        for (int i = 0; i < n2; i++) s2.add(sc.nextInt());
        s1.retainAll(s2);
        if (s1.isEmpty()) System.out.println("EMPTY");
        else {
            StringBuilder sb = new StringBuilder();
            for (int x : s1) {
                if (sb.length() > 0) sb.append(" ");
                sb.append(x);
            }
            System.out.println(sb);
        }
    }
}

